previewCss:
.darma-loader-darma-custom-509 {color: var(--loader-color, #0ea5e9);
  --loader-secondary-color: #67e8f9;
  --loader-bg: #ffffff;
   width: 16px;
   aspect-ratio: 1;
   background: var(--loader-color, #0ea5e9);
   position: relative;
   animation: darma-loader-darma-custom-509-l5-0 2s infinite linear;
}
.darma-loader-darma-custom-509:before  {
  content: "";
   position: absolute;
   inset: 0;
   background: var(--loader-secondary-color, #67e8f9);
   transform: translate(30px) rotate(0);
   animation: darma-loader-darma-custom-509-l5-1 .5s infinite }
@keyframes darma-loader-darma-custom-509-l5-0  {
  100% {transform: rotate(1turn)}
}
@keyframes darma-loader-darma-custom-509-l5-1  {
  100% {transform: translate(30px) rotate(.25turn)}
}

